SELECT p.word_id
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.next_review_time IS NOT NULL AND p.next_review_time <= #{now}
ORDER BY p.next_review_time ASC
LIMIT 1

SELECT p.word_id
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.is_wrong = 1 AND p.next_review_time IS NOT NULL AND p.next_review_time <= #{now}
ORDER BY p.next_review_time ASC
LIMIT #{limit}

SELECT p.word_id
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.next_review_time IS NOT NULL AND p.next_review_time <= #{now}

  AND p.word_id NOT IN

    #{id}


ORDER BY p.next_review_time ASC
LIMIT #{limit}

SELECT COUNT(*)
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.is_wrong = 1 AND p.next_review_time IS NOT NULL AND p.next_review_time <= #{now}

SELECT COUNT(*)
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.next_review_time IS NOT NULL AND p.next_review_time <= #{now}

SELECT COUNT(*)
FROM word w
WHERE w.unit_id = #{unitId}
  AND NOT EXISTS (
    SELECT 1 FROM student_word_progress p
    WHERE p.word_id = w.id AND p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  )

SELECT p.word_id
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.next_review_time IS NOT NULL AND p.next_review_time <= #{now}
ORDER BY p.in_reinforcement DESC, p.next_review_time ASC
LIMIT #{limit}

SELECT p.word_id
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.in_reinforcement = 1

  AND p.word_id NOT IN

    #{id}


ORDER BY p.last_error_time DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND DATE(p.created_at) = CURDATE()

SELECT COUNT(*)
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.correct_count >= 1

SELECT COUNT(DISTINCT p.word_id)
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND (p.in_reinforcement = 1 OR p.wrong_count > 0)

SELECT COALESCE(SUM(p.correct_count), 0) as correctSum, COALESCE(SUM(p.wrong_count), 0) as wrongSum
FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id
INNER JOIN unit u ON u.id = w.unit_id AND u.book_id = #{bookId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}

SELECT p.word_id FROM student_word_progress p
INNER JOIN word w ON w.id = p.word_id AND w.unit_id = #{unitId}
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.next_review_time IS NOT NULL AND p.next_review_time <= #{now}
ORDER BY p.next_review_time ASC
LIMIT #{limit}

SELECT p.word_id FROM student_word_progress p
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.next_review_time IS NOT NULL AND p.next_review_time <= #{now}
ORDER BY p.next_review_time ASC
LIMIT #{limit}

SELECT p.word_id FROM student_word_progress p
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.correct_count >= 1
ORDER BY p.last_study_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM student_word_progress p
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.correct_count >= 1

SELECT p.word_id
FROM student_word_progress p
WHERE p.tenant_id = #{tenantId} AND p.user_id = #{userId}
  AND p.is_wrong = 1 AND p.last_error_time IS NOT NULL AND p.last_error_time >= #{since}
ORDER BY p.last_error_time DESC
LIMIT #{limit}

SELECT COUNT(DISTINCT e.word_id)
FROM error_log e
INNER JOIN student_word_progress p
  ON p.tenant_id = e.tenant_id AND p.user_id = e.user_id AND p.word_id = e.word_id
WHERE e.tenant_id = #{tenantId}
  AND e.user_id = #{userId}
  AND DATE(e.created_at) = #{date}
  AND p.is_wrong = 1

    AND UPPER(e.error_type) = #{errorType}
